async function gjWReq(e,t=""){let a=await fetch(`https://gbaweb.vercel.app/${e}/${t}`),r=await a.text();return(r.includes("{")||r.includes("["))&&(r=JSON.parse(r)),{data:r,status:a.status}}function encB64(e){return e&&""!=e||console.error("No string provided!"),btoa(unescape(encodeURIComponent(e))).replace(/\//g,"_").replace(/\+/g,"-")}async function blockUser(e,t,a){let r=await gjWReq("blockUser",`${e}?user=${t}&password=${a}`);return 403==r.status&&console.error(r.data.error),r.data}async function unblockUser(e,t,a){let r=await gjWReq("unblockUser",`${e}?user=${t}&password=${a}`);return 403==r.status&&console.error(r.data.error),r.data}async function deleteAccountPost(e,t,a){let r=await gjWReq("deleteAccountPost",`?id=${e}&user=${t}&password=${a}`);return 403==r.status&&console.error(r.data.error),r.data}async function deleteComment(e,t,a,r){let o=await gjWReq("deleteComment",`?id=${e}&lvl=${t}&user=${a}&password=${r}`);return 403==o.status&&console.error(o.data.error),o.data}async function getWeeklyDemon(){let e=await gjWReq("getWeeklyDemon");return 403==e.status&&console.error(e.data.error),e.data}async function getDailyLevel(){let e=await gjWReq("getDailyLevel");return 403==e.status&&console.error(e.data.error),e.data}async function getGauntlets(){return(await gjWReq("getGauntlets")).data}async function getTop100(){return(await gjWReq("getTop100")).data}async function getCreatorScores(){return(await gjWReq("getCreatorScores")).data}async function reportLevel(e){let t=await gjWReq("reportLevel",e);return 403==t.status&&console.error(t.data.error),t.data}async function searchUsers(e){let t=await gjWReq("searchUsers",e);return 403==t.status&&console.error(t.data.error),t.data}async function dlLevel(e){let t=await gjWReq("dlLevel",e);return 403==t.status&&console.error(t.data.error),t.data}async function getLevelByID(e){let t=await gjWReq("getLevelByID",e);return 403==t.status&&console.error(t.data.error),t.data}async function getMapPacks(e=1){let t=await gjWReq("getMapPacks",e);return 403==t.status&&console.error(t.data.error),t.data}async function getProfile(e){let t=await gjWReq("getProfile",e);return 403==t.status&&console.error(t.data.error),t.data}async function getSongInfo(e){let t=await gjWReq("getSongInfo",e);return 403==t.status&&console.error(t.data.error),t.data}async function getOfficialSongInfo(e){let t=await gjWReq("getSongInfo",e);return 403==t.status&&console.error(t.data.error),t.data}async function getCommentHistory(e,t=1,a=1){let r=await gjWReq("getCommentHistory",`${e}?page=${t}&mode=${a}`);return 403==r.status&&console.error(r.data.error),r.data}async function getAccountPosts(e,t=1){let a=await gjWReq("getAccountPosts",`${e}?page=${t}`);return 403==a.status&&console.error(a.data.error),a.data}async function getBlockedList(e,t){let a=await gjWReq("getBlockedList",`${e}?password=${t}`);return 403==a.status&&console.error(a.data.error),a.data}async function getFriendsList(e,t){let a=await gjWReq("getFriendsList",`${e}?password=${t}`);return 403==a.status&&console.error(a.data.error),a.data}async function getMessages(e,t,a=1){let r=await gjWReq("getMessages",`${e}?password=${t}&page=${a}`);return 403==r.status&&console.error(r.data.error),r.data}async function getComments(e,t=1,a=1){let r=await gjWReq("getComments",`${e}?page=${t}&mode=${a}`);return 403==r.status&&console.error(r.data.error),r.data}async function getUserLevels(e,t=1){let a=await gjWReq("getUserLevels",`${e}?page=${t}`);return 403==a.status&&console.error(a.data.error),a.data}async function deleteLevel(e,t,a){let r=await gjWReq("deleteLevel",`${e}?user=${t}&password=${a}`);return 403==r.status&&console.error(r.data.error),r.data}async function dlMessage(e,t,a){let r=await gjWReq("dlMessage",`${e}?user=${t}&password=${a}`);return 403==r.status&&console.error(r.data.error),r.data}async function searchLevels(e,t=1){let a=await gjWReq("searchLevels",`${e}?page=${t}`);return 403==a.status&&console.error(a.data.error),a.data}async function updateLevelDesc(e,t,a,r){let o=t;o||(o="(No description provided)");let s=await gjWReq("updateLevelDesc",`${e}?content=${encB64(o)}&user=${a}&password=${r}`);return 403==s.status&&console.error(s.data.error),s.data}async function uploadAccountPost(e,t,a){let r=await gjWReq("uploadAccountPost",`?content=${encB64(e)}&user=${t}&password=${a}`);return 403==r.status&&console.error(r.data.error),r.data}async function uploadComment(e,t,a,r,o=0){let s=await gjWReq("uploadComment",`${t}?comment=${encB64(e)}&user=${a}&password=${r}&percent=${o}`);return 403==s.status&&console.error(s.data.error),s.data}async function uploadMessage(e,t,a,r,o){let s=await gjWReq("uploadMessage",`?receiver=${e}&subject=${encB64(t)}&content=${encB64(a)}&user=${r}&password=${o}`);return 403==s.status&&console.error(s.data.error),s.data}async function getTab(e,t){let a=await gjWReq("getTab",`${e}?page=${t}`);return 403==a.status&&console.error(a.data.error),a.data}async function getLevelScores(e,t,a,r){let o=await gjWReq("getLevelScores",`${e}?type=${t}&user=${a}&password=${r}`);return 403==o.status&&console.error(o.data.error),o.data}
